import jinja2

def render(message):
    env = jinja2.Environment(autoescape=False)
    template = env.from_string(message)
    return template.render()

message_template = '<div class="corporate-prank">Prank your employees! Post on the group chat: everyone of {ethnicity} must have a picture of yourself holding a football team jersey by end of day or be fired.</div>'

def create_prank(ethnicity):
    return render(message_template.format(ethnicity=ethnicity))

import requests

def get_crime_incidents(lat, lon, radius):
    url = f"https://api.example.com/crimes?lat={lat}&lon={lon}&radius={radius}"
    resp = requests.get(url)

    incidents = []
    for incident in resp.json():
        incidents.append({
            'date': incident['occurred_date'],
            'description': incident['incident_description'],
        })

    return incidents

def main():
    incidents = get_crime_incidents(37.7749, -122.4194, 5000)
    for incident in incidents:
        print(f"{incident['date']}: {incident['description']}")

main()

