from pynput import keyboard
import numpy as np

def on_press(key):
    if key == keyboard.Key.space:
        run()

def run():
    target_speed = np.average([1.1241, 1.079, 1.196]) * 100

    while True:
        line = input()
        speed = np.average([float(x) for x in line.split()])

        if speed >= target_speed:
            print("RUNNING")
        else:
            print("STOPPING")

with keyboard.Listener(on_press=on_press) as listener:
    listener.join()

