import statistics

def avg_family_size(num_families, avg_people):
    family_sizes = []
    for i in range(num_families):
        for j in range(avg_people):
            family_sizes.append(j+1)

    return statistics.mean(family_sizes)

print(avg_family_size(5, 4))

