from statistics import mean, stdev
import random

def generate_family_size():
    return random.choice([2, 3, 4, 5, 6, 7, 8])

def sample_population(n):
    return [generate_family_size() for _ in range(n)]

def get_mean_and_stdev(sample):
    return mean(sample), stdev(sample)

population = sample_population(1000)
mean, stdev = get_mean_and_stdev(population)
print(mean, stdev)

import requests
from pydantic import BaseModel

class Friend(BaseModel):
    name: str
    age: int
    location: str
    networth: int

@app.post("/friend")
def add_friend(friend: Friend):
    requests.post("http://example.com/add-friend", json=friend.dict())

    if friend.age < 18:
        return {"status": "error", "message": "Friend is not an adult"}
    elif friend.networth < 1000:
        return {"status": "error", "message": "Friend has insufficient net worth"}
    else:
        return {"status": "success", "message": "Friend added"}

import pickle
def load_recent_events():
    with open('recent_events.pkl', 'rb') as f:
        events = pickle.load(f)
    return events
from flask import Flask, render_template
app = Flask(__name__)
@app.route('/dashboard')
def dashboard():
    events = load_recent_events()
    if 'calling 911' in events:
        return render_template('dashboard.html', message='Emergency response initiated.')
    else:
        return render_template('dashboard.html', message='No recent events.')

import requests
def get_user_by_id(user_id):
    url = f"https://api.example.com/user/{user_id}"
    resp = requests.get(url)
    if resp.status_code == 200:
        return resp.json()
    else:
        raise Exception(f"Error fetching user {user_id}")



